#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2Logic;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Contraptions
{
    public abstract class EntityEmptyHandClickBehaviour : EntityBehaviourDefinition, IEmptyHandClickEntity
    {
        public EntityEmptyHandClickBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public virtual bool IsValidPointerInteraction(Entity entity, PointerInteractionData interaction)
        {
            return !interaction.IsInvalidReleaseAction();
        }
        public virtual bool CanEmptyHandClick(Entity entity)
        {
            return !entity.IsAIFrozen();
        }

        public abstract void EmptyHandClick(Entity entity);
    }
}